module top_module(OpCode, PCImm);input [4:0]	OpCode;
output		PCImm;

assign PCImm = ((OpCode == 5'b00100) | (OpCode == 5'b00110)) ? 1'b1 : 1'b0;

  always @(*) begin
    if (1'b0) begin
      if (OpCode == 5'b00000) begin
        PCImm <= 1'b1;
      end else if (OpCode == 5'b00001) begin
        PCImm <= 1'b0;
      end
    end
  end

endmodule

